 70→     * Dify Blocking 模式。
 71→     */
 72→    private function analyzeDify(string $content, string $systemPrompt): string
 73→    {
 74→        $difyBaseUrl = config('vertex_ai.dify_url');
 75→        $difyKey = config('vertex_ai.dify_key');
 76→
 77→        if (empty($difyBaseUrl) || empty($difyKey)) {
 78→            Log::error('[lbl][0416-AI日报][AiAnalysis][Dify] dify_url or dify_key not configured');
 79→            return '';
 80→        }
 81→
 82→        $difyUrl = rtrim($difyBaseUrl, '/').'/chat-messages';
 83→
 84→        $payload = json_encode([
 85→            'inputs' => ['system_prompt' => $systemPrompt ?: ' '],
 86→            'query' => $content,
 87→            'response_mode' => 'blocking',
 88→            'conversation_id' => '',
 89→            'user' => 'oa-ai-chat',
 90→        ], JSON_UNESCAPED_UNICODE);
 91→
 92→        Log::info('[lbl][0416-AI日报][AiAnalysis][Dify][CALL] blocking 请求 Dify', [
 93→            'url' => $difyUrl,
 94→            'query_len' => mb_strlen($content),
 95→            'prompt_len' => mb_strlen($systemPrompt),
 96→        ]);
 97→
 98→        $ch = curl_init($difyUrl);
 99→        curl_setopt_array($ch, [
100→            CURLOPT_POST => true,
101→            CURLOPT_POSTFIELDS => $payload,
102→            CURLOPT_HTTPHEADER => ['Content-Type: application/json', 'Authorization: Bearer '.$difyKey],
103→            CURLOPT_RETURNTRANSFER => true,
104→            CURLOPT_TIMEOUT => 120,
105→        ]);
106→
107→        $response = curl_exec($ch);
108→        $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
109→        $curlError = $response === false ? curl_error($ch) : '';
110→        curl_close($ch);
111→
112→        if ($curlError) {
113→            Log::error('[lbl][0416-AI日报][AiAnalysis][Dify] curl error', ['url' => $difyUrl, 'error' => $curlError]);
114→            return '';
115→        }
116→
117→        $result = json_decode($response, true);
118→        if (!is_array($result)) {
119→            Log::error('[lbl][0416-AI日报][AiAnalysis][Dify] invalid response', ['http_code' => $httpCode, 'raw' => mb_substr($response, 0, 1000)]);
120→            return '';
121→        }
122→
123→        // Dify 错误响应：有 message 但无 answer
124→        if (isset($result['message']) && !isset($result['answer'])) {
125→            Log::error('[lbl][0416-AI日报][AiAnalysis][Dify] error', ['http_code' => $httpCode, 'result' => $result]);
126→            return '';
127→        }
128→
129→        $answer = $result['answer'] ?? '';
130→        Log::info('[lbl][0416-AI日报][AiAnalysis][Dify] blocking done', ['http_code' => $httpCode, 'answer_len' => mb_strlen($answer)]);
131→
132→        return $answer;
133→    }
