432→        $context = stream_context_create([
433→            'http' => [
434→                'header' => 'Metadata-Flavor: Google',
435→                'timeout' => 5,
436→            ],
437→        ]);
438→
439→        $response = @file_get_contents($url, false, $context);
440→        if ($response === false) {
441→            Log::error('[lbl][0416-AI日报][AiAnalysis] failed to get access token from metadata server');
442→            return '';
443→        }
444→
445→        $data = json_decode($response, true);
446→        return $data['access_token'] ?? '';
447→    }
