131→    public function taskTest(Request $request): StreamedResponse
132→    {
133→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
134→        if (!$this->inWhitelist($sfuserId)) {
135→            return $this->sseError('无权限');
136→        }
137→
138→        $systemPrompt = $request->input('system_prompt', '');
139→        $dimension = $request->input('dimension', 'department');
140→        $reportRange = $request->input('report_range', 'today');
141→        $groupKey = $request->input('group_key', '');
142→
143→        // 计算日期范围
144→        $today = now()->toDateString();
145→        [$startDate, $endDate] = match ($reportRange) {
146→            'last_3_days' => [now()->subDays(2)->toDateString(), $today],
147→            'last_7_days' => [now()->subDays(6)->toDateString(), $today],
148→            default => [$today, $today],
149→        };
150→
151→        // 拉取该用户能看到日报的全部员工
152→        $dailyService = app(DailyReportService::class);
153→        $subordinates = $dailyService->getSubordinates($sfuserId);
154→        // group_users 是二维数组 [groupId => [userId, ...]]，需要 flatten
155→        $groupUserIds = [];
156→        foreach ($subordinates['group_users'] as $userIds) {
157→            $groupUserIds = array_merge($groupUserIds, $userIds);
158→        }
159→        $targetUserIds = array_unique(array_merge(
160→            $subordinates['direct_subordinates'],
161→            $subordinates['depart_subordinates'],
162→            $subordinates['other_subordinates'],
163→            $subordinates['focus_users'],
164→            $groupUserIds
165→        ));
166→
167→        if (empty($targetUserIds)) {
168→            return $this->sseError('没有可查看的员工');
169→        }
170→
171→        // 拉取日报数据
172→        $data = $dailyService->getOthersDailyReportListEnable($startDate, $endDate, $sfuserId, $targetUserIds, 10000);
173→        if (empty($data) || empty($data['reports']) || empty($data['reports']['report_list'])) {
174→            return $this->sseError('所选日期范围内没有日报数据');
175→        }
176→
177→        $reportList = $data['reports']['report_list'];
178→        $reportSfuserIds = array_unique(array_column($reportList, 'sfuser_id'));
179→
180→        // 构建分组映射
181→        $sfuserGroupMap = $this->buildGroupMap($reportSfuserIds, $dimension);
182→
183→        // 按维度分组日报
184→        $grouped = [];
185→        foreach ($reportList as $report) {
186→            $uid = $report['sfuser_id'];
187→            $key = $sfuserGroupMap[$uid]['key'] ?? 'unknown';
188→            $grouped[$key]['name'] = $sfuserGroupMap[$uid]['name'] ?? '';
189→            $grouped[$key]['reports'][] = $report;
190→        }
191→
192→        // 找到用户选中的分组，找不到则取第一个
193→        $targetGroup = $grouped[$groupKey] ?? reset($grouped);
194→        if (empty($targetGroup) || empty($targetGroup['reports'])) {
195→            return $this->sseError('所选分组没有日报数据');
196→        }
197→
198→        // 构建带加密标记的内容（oa-core 负责解密）
199→        // group_name 在数据库中是加密值，用 markEncrString 包裹后随 message 一起发给 oa-core 解密
200→        $groupNameMarked = EncryptService::app()->markEncrString($targetGroup['name']);
201→        $content = "【分组：{$groupNameMarked}】\n\n";
202→        $no = 0;
203→        foreach ($targetGroup['reports'] as $report) {
204→            $nickname = $report['data']['nickname'] ?? '';
205→            if (empty($nickname)) {
206→                continue;
207→            }
208→            $nickname = EncryptService::app()->markEncrString(e($nickname));
209→            $reportContent = EncryptService::app()->markEncrString($report['content']);
210→            ++$no;
211→            $content .= $no.'、 '.$nickname."\n".$reportContent."\n\n";
212→        }
213→
214→        if ($no === 0) {
215→            return $this->sseError('该分组没有有效的日报内容');
216→        }
217→
218→        \Log::info('[lbl][0416-AI日报][AiEmail][TEST] 开始测试 Prompt', [
219→            'sfuser_id' => $sfuserId,
220→            'dimension' => $dimension,
221→            'group_key' => $groupKey,
222→            'group_name' => $targetGroup['name'],
223→            'report_count' => $no,
224→            'content_len' => mb_strlen($content),
225→        ]);
226→
227→        // 从 MailConfig 读取 sfuser_authorized_token，与定时邮件 Job 使用同一个 token 解密
228→        $mc = MailConfig::where('type', "daily_report_{$sfuserId}")->first();
229→        $sfuserToken = $mc ? Arr::get($mc->config, 'sfuser_authorized_token', '') : '';
230→        if (empty($sfuserToken)) {
231→            return $this->sseError('未配置邮件授权 Token，请先在管理后台配置邮件');
232→        }
233→
234→        // 调用 oa-core ai/chat，带 decrypt_config + compress，streaming 模式
235→        $reportCount = $no;
236→        return response()->stream(function () use ($content, $systemPrompt, $dimension, $reportRange, $startDate, $endDate, $reportCount, $sfuserToken) {
237→            ignore_user_abort(true);
238→
239→            // 首帧：发送测试信息摘要（维度、日期范围、日报数量）
240→            $dimensionLabel = $dimension === 'direct_manager' ? '按直接主管' : '按部门';
241→            $rangeLabel = match ($reportRange) {
242→                'last_3_days' => '近3天',
243→                'last_7_days' => '近7天',
244→                default => '今日',
245→            };
246→            $dateRange = $startDate === $endDate ? $startDate : "{$startDate} ~ {$endDate}";
247→            $this->echoData(0, '', [
248→                'type' => 'meta',
249→                'summary' => "{$dimensionLabel} · {$rangeLabel}（{$dateRange}）· {$reportCount}份日报",
250→            ]);
251→
252→            // 通过 AiStreamService 调用 oa-core，带解密+压缩参数
253→            AiStreamService::streamFromCore(
254→                $content,
255→                $systemPrompt,
256→                function (string $chunk) {
257→                    $this->echoData(0, '', ['type' => 'chat', 'content' => $chunk]);
258→                },
259→                [
260→                    'decrypt_config' => [
261→                        'obj' => '$this',
262→                        'decrypt_columns' => [],
263→                        'partly_decrypt_columns' => ['message'],
264→                        'tokens' => [$sfuserToken],
265→                        'operation' => 'send_email',
266→                    ],
267→                    'compress' => true,
268→                ]
269→            );
270→
271→            // 结束帧
272→            $this->echoData(0, '', ['type' => 'done']);
273→        }, 200, [
274→            'Content-Type' => 'text/event-stream',
275→            'Cache-Control' => 'no-cache',
276→            'X-Accel-Buffering' => 'no',
277→        ]);
278→    }
