284→    private function buildGroupMap(array $sfuserIds, string $dimension): array
285→    {
286→        if (empty($sfuserIds)) {
287→            return [];
288→        }
289→
290→        $map = [];
291→
292→        if ($dimension === 'direct_manager') {
