306→                ->select('id', 'department_id')
307→                ->get();
308→            $deptIds = $users->pluck('department_id')->filter()->unique()->values()->toArray();
309→            $deptNames = [];
310→            if (!empty($deptIds)) {
311→                $deptNames = DB::table('job_departments')
312→                    ->whereIn('department_id', $deptIds)
313→                    ->pluck('department_name', 'department_id')
314→                    ->toArray();
315→            }
316→            foreach ($users as $user) {
317→                $deptId = $user->department_id ?: 0;
318→                $deptName = $deptNames[$deptId] ?? '未分配部门';
319→                $map[$user->id] = [
320→                    'key' => "dept_{$deptId}",
321→                    'name' => $deptName,
