329→    private function echoData(int $errCode, string $errMsg, array $data): void
330→    {
331→        echo 'data: '.json_encode(['error_code' => $errCode, 'error_msg' => $errMsg, 'data' => $data], JSON_UNESCAPED_UNICODE).PHP_EOL.PHP_EOL;
332→        ob_flush();
333→        flush();
334→    }
