336→    private function sseError(string $msg): StreamedResponse
337→    {
338→        return response()->stream(function () use ($msg) {
339→            $this->echoData(1, $msg, []);
340→        }, 200, [
341→            'Content-Type' => 'text/event-stream',
342→            'Cache-Control' => 'no-cache',
343→            'X-Accel-Buffering' => 'no',
